function formatRevenueShort(value) {
  const num = Number(value) || 0;
  if (num >= 10000000) return `Rs ${(num / 10000000).toFixed(2)}Cr`;
  if (num >= 100000) return `Rs ${(num / 100000).toFixed(2)}L`;
  return `Rs ${num.toLocaleString('en-IN')}`;
}

