function TransactionFormModal({ transaction, accounts, onClose, onSave }) {
  const [form, setForm] = useState(transaction ? {
    ...transaction,
    entrySide: transaction.debit > 0 ? 'Debit' : 'Credit',
    amount: String(transaction.debit > 0 ? transaction.debit : transaction.credit),
  } : {
    transactionNo: '',
    date: '07 May 2024',
    accountName: accounts[0] ?? 'Sunlight Enterprises',
    type: 'Receipt',
    referenceNo: '',
    description: '',
    entrySide: 'Credit',
    amount: '75000',
    status: 'Completed',
  });
  const updateField = (field, value) => setForm((current) => ({ ...current, [field]: value }));

  return (
    <div className="fixed inset-0 z-90 flex items-center justify-center bg-[#111827]/45 p-4 backdrop-blur-[2px]">
      <div className="w-full max-w-[720px] rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between border-b border-[#edf2f8] px-6 py-5"><h2 className="font-display text-[20px] font-extrabold text-[#111827]">{transaction ? 'Edit Transaction' : 'New Transaction'}</h2><button type="button" onClick={onClose} className="text-[#7585a2]" aria-label="Close transaction editor"><X className="size-5" /></button></div>
        <div className="grid gap-4 p-6 sm:grid-cols-2">
          <ModalTextInput label="Transaction No." value={form.transactionNo} onChange={(value) => updateField('transactionNo', value)} placeholder="Auto if blank" />
          <ModalTextInput label="Date" value={form.date} onChange={(value) => updateField('date', value)} placeholder="07 May 2024" />
          <ReportSelect label="Account" value={form.accountName} onChange={(value) => updateField('accountName', value)} options={accounts.length ? accounts : ['Sunlight Enterprises']} />
          <ReportSelect label="Type" value={form.type} onChange={(value) => updateField('type', value)} options={['Receipt', 'Payment', 'Transfer', 'Journal Entry']} />
          <ModalTextInput label="Reference No." value={form.referenceNo} onChange={(value) => updateField('referenceNo', value)} placeholder="RCPT-0891" />
          <ModalTextInput label="Description" value={form.description} onChange={(value) => updateField('description', value)} placeholder="Transaction description" />
          <ReportSelect label="Entry Side" value={form.entrySide} onChange={(value) => updateField('entrySide', value)} options={['Credit', 'Debit']} />
          <ModalTextInput label="Amount" value={String(form.amount)} onChange={(value) => updateField('amount', value)} placeholder="0" />
          <ReportSelect label="Status" value={form.status} onChange={(value) => updateField('status', value)} options={['Completed', 'Pending', 'Reconciled']} />
        </div>
        <div className="flex flex-col justify-end gap-3 border-t border-[#edf2f8] px-6 py-5 sm:flex-row"><button type="button" onClick={onClose} className="h-10 rounded-[8px] border border-[#d9e4f2] bg-white px-6 text-[13px] font-extrabold text-[#233a6b]">Cancel</button><button type="button" onClick={() => onSave(form)} className="inline-flex h-10 items-center justify-center gap-2 rounded-[8px] bg-[#0d9f4a] px-6 text-[13px] font-extrabold text-white"><Save className="size-4" />Save Transaction</button></div>
      </div>
    </div>
  );
}

function TransactionDetailModal({ transaction, onClose, onEdit, onNotify }) {
  if (!transaction) {
    return null;
  }

  return (
    <DetailModalShell title={transaction.transactionNo} onClose={onClose}>
      <div className="grid gap-3 sm:grid-cols-2">
        <InfoCell label="Date" value={transaction.date} />
        <InfoCell label="Account" value={transaction.accountName} />
        <InfoCell label="Type" valueNode={<TransactionTypeBadge type={transaction.type} />} />
        <InfoCell label="Reference" value={transaction.referenceNo} />
        <InfoCell label="Debit" value={formatLedgerAmount(transaction.debit)} />
        <InfoCell label="Credit" value={formatLedgerAmount(transaction.credit)} />
        <InfoCell label="Balance" value={formatLedgerCurrency(transaction.balance)} />
        <InfoCell label="Status" valueNode={<TransactionStatusBadge status={transaction.status} />} />
      </div>
      <p className="mt-5 rounded-[10px] border border-[#e7eef7] bg-[#f8fbff] p-4 text-[13px] font-bold leading-6 text-[#53647f]">{transaction.description}</p>
      <div className="mt-5 flex flex-col justify-end gap-3 sm:flex-row">
        <button type="button" onClick={() => onNotify(`${transaction.transactionNo} voucher downloaded`)} className="h-10 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#233a6b]">Download Voucher</button>
        <button type="button" onClick={onEdit} className="h-10 rounded-[8px] bg-[#0d9f4a] px-5 text-[13px] font-extrabold text-white">Edit Transaction</button>
      </div>
    </DetailModalShell>
  );
}

function formatLedgerAmount(value) {
  return Number(value || 0) > 0 ? Number(value).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '-';
}

function formatLedgerCurrency(value) {
  return Number(value || 0).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function SettingsMasterPage({ activeSection, onOpenSection, onNotify }) {
  if (activeSection === 'Payment Settings') {
    return <PaymentSettingsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Payment Mode' || activeSection === 'Master Type') {
    return <PaymentModeListPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Business Information') {
    return <BusinessInformationSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Branches') {
    return <BranchManagementSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Company Profile') {
    return <CompanyProfileSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Financial Year') {
    return <FinancialYearSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'System Settings') {
    return <SystemSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Date & Time Format') {
    return <DateTimeFormatSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Currency Settings') {
    return <CurrencySettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Language Settings') {
    return <LanguageSettingsPage onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Settings Users') {
    return <SettingsUsersPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Settings Roles & Permissions') {
    return <SettingsRolesPermissionsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Settings User Activity Log') {
    return <SettingsUserActivityLogPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection === 'Settings IP Restrictions') {
    return <SettingsIpRestrictionsPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (settingsCardGroups.some((group) => group.items.some((item) => item.key === activeSection))) {
    return <SettingsStandaloneInlinePage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  if (activeSection !== 'Settings') {
    return <SettingsCategoryPlaceholderPage activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />;
  }

  const settingsOptionIcons = {
    'Company Profile': Home,
    'Business Information': FileText,
    Branches: MapPin,
    'Financial Year': CalendarDays,
    'Settings Users': Users,
    'Settings Roles & Permissions': ShieldCheck,
    'Settings User Activity Log': Clock3,
    'Settings IP Restrictions': LockKeyhole,
    'System Settings': Settings,
    'Date & Time Format': CalendarDays,
    'Currency Settings': IndianRupee,
    'Language Settings': MessageSquareMore,
    'Chart of Accounts': ReceiptText,
    'Account Prefix': FileText,
    'Opening Balance': IndianRupee,
    'Payment Settings': ReceiptText,
    'Payment Mode': ReceiptText,
    'Product Categories': Boxes,
    'Units of Measurement': Wrench,
    'Tax Settings': ReceiptText,
    'Stock Settings': Boxes,
    'Project Status': FolderKanban,
    'Project Types': FolderKanban,
    'Task Priorities': Flag,
    'Milestone Settings': Trophy,
    'Email Settings': Mail,
    'SMS Settings': MessageSquareMore,
    'WhatsApp Settings': Phone,
    'Notification Settings': Bell,
    'Document Settings': FileText,
    'Approval Settings': ShieldCheck,
    'Backup & Restore': RefreshCw,
    'System Maintenance': Wrench,
  };

  const settingsGroupIconTone = {
    'Organization Settings': 'bg-[#e8f8eb] text-[#14853a]',
    'User & Access Management': 'bg-[#e8f2ff] text-[#0b65e5]',
    'General Settings': 'bg-[#f3edff] text-[#7b46dc]',
    'Accounts Settings': 'bg-[#fff0dc] text-[#ea580c]',
    'Inventory Settings': 'bg-[#e7faf8] text-[#0f766e]',
    'Project Settings': 'bg-[#ffeaf4] text-[#db2777]',
    'Communication Settings': 'bg-[#e9f8ec] text-[#15803d]',
    'Other Settings': 'bg-[#fff7e8] text-[#ca8a04]',
  };

  return <SettingsSetupPage onOpenSection={onOpenSection} onNotify={onNotify} />;
}

function SettingsStandaloneInlinePage({ activeSection, onOpenSection, onNotify }) {
  const activeGroup = getSettingsGroupForSection(activeSection);
  const title = getSettingsDisplayLabel(activeSection);

  return (
    <div className="space-y-4">
      <PageHeading
        title={title}
        crumbs={[
          { label: 'Dashboard', onClick: () => onOpenSection('Dashboard') },
          { label: 'Settings', onClick: () => onOpenSection('Settings') },
          ...(activeGroup ? [{ label: activeGroup.title }] : []),
          { label: title },
        ]}
      />

      <SettingsCategoryTabs
        activeGroupTitle={activeGroup?.title}
        activeSection={activeSection}
        onOpenSection={onOpenSection}
      />
      {activeGroup ? (
        <SettingsSubcategoryTabs
          groupTitle={activeGroup.title}
          activeSection={activeSection}
          onSelectSection={(section) => onOpenSection(getSettingsRouteKey(section))}
        />
      ) : null}
      <SettingsInlineContent activeSection={activeSection} onOpenSection={onOpenSection} onNotify={onNotify} />

      <DashboardFooter />
    </div>
  );
}

function SettingsNavigationRail({ activeSection, onOpenSection, onNotify }) {
  const activeGroup = getSettingsGroupForSection(activeSection);
  const handleOpenSection = typeof onOpenSection === 'function' ? onOpenSection : () => {};
  const handleNotify = typeof onNotify === 'function' ? onNotify : () => {};

  if (!activeGroup) {
    return null;
  }

  return (
    <section className={`settings-navigation-rail ${panelClass} overflow-hidden p-3 sm:p-4`}>
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <p className="font-display text-[16px] font-extrabold text-[#1e3261]">{activeGroup.title}</p>
          <p className="mt-1 text-[12px] font-bold text-[#6f7f98]">Sirf is category ki sub-categories yahan horizontally dikhengi.</p>
        </div>
        <button
          type="button"
          onClick={() => {
            handleOpenSection('Settings');
            handleNotify('Settings home opened');
          }}
          className="inline-flex h-10 w-full items-center justify-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-4 text-[12px] font-extrabold text-[#284276] transition hover:bg-[#f8fbff] sm:w-auto"
        >
          <ChevronLeft className="size-4" />
          All Settings
        </button>
      </div>

      <div className="-mx-1 mt-4 overflow-x-auto px-1 pb-1">
        <div className="flex min-w-max gap-3 xl:min-w-0 xl:flex-wrap">
          {activeGroup.items.map((item) => {
            const routeKey = getSettingsRouteKey(item.key);
            const isActive = activeSection === item.key || (activeSection === 'Master Type' && item.key === 'Payment Mode');
            return (
              <button
                key={item.key}
                type="button"
                onClick={() => handleOpenSection(routeKey)}
                className={cx(
                  'inline-flex h-[52px] min-w-[164px] items-center justify-between gap-3 rounded-[12px] border px-4 text-left shadow-[0_10px_20px_rgba(17,39,84,0.04)] transition hover:-translate-y-0.5 xl:flex-1',
                  isActive
                    ? 'border-[#bcefd1] bg-[#f1fff6] text-[#087a39] ring-2 ring-[#dff6e7]'
                    : 'border-[#d9e4f2] bg-white text-[#314a79] hover:border-[#c8d8ed] hover:bg-[#f8fbff]',
                )}
              >
                <span className="inline-flex min-w-0 items-center gap-3">
                  <span className={cx('size-2 rounded-full', isActive ? 'bg-[#14b84c]' : 'bg-[#b9c4d6]')} />
                  <span className="truncate text-[13px] font-extrabold">{item.label}</span>
                </span>
                <ChevronRight className={cx('size-4 shrink-0', isActive ? 'text-[#14b84c]' : 'text-[#9aa8bc]')} />
              </button>
            );
          })}
        </div>
      </div>
    </section>
  );
}

function SettingsFieldLabel({ label, required = false }) {
  return (
    <span className="mb-2 block text-[12px] font-extrabold text-[#34466c]">
      {label}
      {required ? <span className="ml-1 text-[#ef4444]">*</span> : null}
    </span>
  );
}

function SettingsInputField({ label, value, onChange, required = false, type = 'text', placeholder = '' }) {
  return (
    <label className="block min-w-0">
      <SettingsFieldLabel label={label} required={required} />
      <input
        type={type}
        value={value}
        onChange={(event) => onChange(event.target.value)}
        placeholder={placeholder}
        className="h-11 w-full rounded-[8px] border border-black/20 bg-white px-4 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
      />
    </label>
  );
}

function SettingsSelectField({ label, value, onChange, options, required = false }) {
  return (
    <label className="block min-w-0">
      <SettingsFieldLabel label={label} required={required} />
      <select
        value={value}
        onChange={(event) => onChange(event.target.value)}
        className="h-11 w-full rounded-[8px] border border-black/20 bg-white px-4 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
      >
        {options.map((option) => (
          <option key={option}>{option}</option>
        ))}
      </select>
    </label>
  );
}

function SettingsTextareaField({ label, value, onChange, required = false, rows = 4 }) {
  return (
    <label className="block min-w-0">
      <SettingsFieldLabel label={label} required={required} />
      <textarea
        value={value}
        onChange={(event) => onChange(event.target.value)}
        rows={rows}
        className="w-full rounded-[8px] border border-black/20 bg-white px-4 py-3 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
      />
    </label>
  );
}

function SettingsSectionCard({ title, children, className = '' }) {
  return (
    <article className={cx(`${panelClass} self-start p-4 sm:p-5`, className)}>
      <h2 className="font-display text-[15px] font-extrabold text-[#111827]">{title}</h2>
      <div className="mt-4">{children}</div>
    </article>
  );
}

