                    <span className={cx('grid size-9 place-items-center rounded-full text-[12px] font-extrabold text-white', row.status === 'Completed' ? 'bg-[#14b84c]' : row.status === 'In Progress' ? 'bg-[#2f80ff]' : 'bg-[#9aa8bc]')}>{index + 1}</span>
