const MONTHS_SHORT = { Jan:0, Feb:1, Mar:2, Apr:3, May:4, Jun:5, Jul:6, Aug:7, Sep:8, Oct:9, Nov:10, Dec:11 };
function isFollowUpOverdue(dateStr) {
  if (!dateStr) return false;
  const parts = dateStr.split(' ');
  if (parts.length !== 3) return false;
  const d = parseInt(parts[0], 10);
  const m = MONTHS_SHORT[parts[1]];
  const y = parseInt(parts[2], 10);
  if (Number.isNaN(d) || m === undefined || Number.isNaN(y)) return false;
  const followUpDate = new Date(y, m, d);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return followUpDate < today;
}

function formatReportDate(value) {
  const date = new Date(`${value}T00:00:00`);
  if (Number.isNaN(date.getTime())) {
    return value;
  }

  return date.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
  });
}

function parseDashboardDate(value) {
  if (!value) {
    return null;
  }

  const normalized = String(value).replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
  const explicitDateMatch = normalized.match(/(\d{1,2}\s+[A-Za-z]{3}\s+\d{4})/);
  if (explicitDateMatch) {
    const explicitDate = new Date(`${explicitDateMatch[1]} 00:00:00`);
    if (!Number.isNaN(explicitDate.getTime())) {
      return explicitDate;
    }
  }

  const isoDateMatch = normalized.match(/(\d{4}-\d{2}-\d{2})/);
  if (isoDateMatch) {
    const isoDate = new Date(`${isoDateMatch[1]}T00:00:00`);
    if (!Number.isNaN(isoDate.getTime())) {
      return isoDate;
    }
  }

  const fallbackDate = new Date(normalized);
  if (!Number.isNaN(fallbackDate.getTime())) {
    return fallbackDate;
  }

  return null;
}

function isDateWithinRange(value, dateFrom, dateTo) {
  const parsedValue = parseDashboardDate(value);
  if (!parsedValue) {
    return true;
  }

  const rangeStart = new Date(`${dateFrom}T00:00:00`);
  const rangeEnd = new Date(`${dateTo}T23:59:59`);
  if (Number.isNaN(rangeStart.getTime()) || Number.isNaN(rangeEnd.getTime())) {
    return true;
  }

  return parsedValue >= rangeStart && parsedValue <= rangeEnd;
}

let cachedEmployeeOptions = null;
let employeeOptionsPromise = null;

function getEmployeeOptions() {
  if (cachedEmployeeOptions) return Promise.resolve(cachedEmployeeOptions);
  if (!employeeOptionsPromise) {
    employeeOptionsPromise = userApi.list({ is_active: true })
      .then((data) => {
        const users = normalizeApiRows(data);
        cachedEmployeeOptions = users.map((user) => ({ label: user.name || user.email, value: String(user.id) }));
        return cachedEmployeeOptions;
      })
      .catch(() => {
        cachedEmployeeOptions = [];
        return cachedEmployeeOptions;
      });
  }
  return employeeOptionsPromise;
}

function useIvrsCheck(excludeId) {
  const [checking, setChecking] = useState(false);
  const [result, setResult] = useState(null);

  const check = async (value) => {
    const ivrs = (value || '').trim();
    if (!ivrs) { setResult(null); return; }
    setChecking(true);
    try {
      const data = await leadApi.list({ search: ivrs });
      const rows = Array.isArray(data) ? data : (data?.results ?? []);
      const match = rows.find((row) => row.ivrs_number === ivrs && row.id !== excludeId);
      setResult(match || 'unique');
    } catch {
      setResult(null);
    } finally {
      setChecking(false);
    }
  };

  return { checking, result, check, reset: () => setResult(null) };
}

function CreateLeadPage({ activeSection = 'Create Lead', onOpenSection, onCancel, onDashboard, onRequestApproval, onNotify }) {
  const [duplicateModalOpen, setDuplicateModalOpen] = useState(false);
  const [duplicateIvrs, setDuplicateIvrs] = useState('');
  const [duplicateLeadMatches, setDuplicateLeadMatches] = useState([]);
  const [duplicateLeadPayload, setDuplicateLeadPayload] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [employeeOptions, setEmployeeOptions] = useState(cachedEmployeeOptions || []);
  const [viewDuplicateLeadId, setViewDuplicateLeadId] = useState(null);
  const ivrsCheck = useIvrsCheck();

  useEffect(() => {
    getEmployeeOptions().then(setEmployeeOptions);
  }, []);

  const handleSubmit = async (event) => {
    event.preventDefault();
    const fd = new FormData(event.currentTarget);
    const mobile = fd.get('mobile_number')?.trim();
    const ivrs = fd.get('ivrs_number')?.trim();

    setSubmitting(true);
    setSubmitError('');
    const payload = {
      customer_name: fd.get('customer_name'),
      mobile_number: mobile,
      ivrs_number: ivrs || undefined,
      alternate_number: fd.get('alternate_number') || undefined,
      email: fd.get('email') || undefined,
      project_name: fd.get('project_name') || undefined,
      project_type: fd.get('project_type') || undefined,
      requirement_details: fd.get('requirement_details') || undefined,
      source: fd.get('source') || undefined,
      estimated_capacity: fd.get('estimated_capacity') || undefined,
      next_follow_up: fd.get('next_follow_up') || undefined,
      assigned_to: fd.get('assigned_to') || undefined,
      status: fd.get('status') || 'New',
      remarks: fd.get('remarks') || undefined,
      address: fd.get('address') || undefined,
      city: fd.get('city') || undefined,
      state: fd.get('state') || undefined,
      latitude: fd.get('latitude') || undefined,
      longitude: fd.get('longitude') || undefined,
    };
    try {
      await leadApi.create(payload);
      onNotify?.('Lead created successfully!');
      onCancel();
    } catch (err) {
      if (err.message?.toLowerCase().includes('ivrs number already exists')) {
        const matches = await leadApi.list({ search: ivrs }).catch(() => null);
        const matchRows = matches ? (Array.isArray(matches) ? matches : matches.results ?? []) : [];
        setDuplicateLeadMatches(matchRows.filter((row) => row.ivrs_number === ivrs));
        setDuplicateLeadPayload(payload);
        setDuplicateIvrs(ivrs);
        setDuplicateModalOpen(true);
      } else {
        setSubmitError(err.message || 'Error saving lead. Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-4 rounded-[14px] bg-white/60 p-3 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="font-display text-[24px] font-extrabold leading-tight text-[#111827] sm:text-[28px]">
            Create Lead
          </h1>
          <div className="mt-2 flex flex-wrap items-center gap-2 text-[13px] font-bold">
            <button
              type="button"
              onClick={onDashboard}
              className="rounded-[7px] border border-black/20 px-2 py-1 text-[#0b65e5] transition hover:bg-white"
            >
              Dashboard
            </button>
            <ChevronRight className="size-3.5 text-[#9aa8bc]" />
            <span className="text-[#53647f]">Lead</span>
            <ChevronRight className="size-3.5 text-[#9aa8bc]" />
            <span className="text-[#111827]">Create Lead</span>
          </div>
        </div>

        <div className="flex flex-col gap-3 sm:flex-row sm:flex-wrap">
          <button
            type="button"
            onClick={onCancel}
            data-action="create-lead-cancel"
            data-route={leadSubRoutes['Lead List']}
            className="inline-flex h-11 w-full items-center justify-center gap-2 rounded-[8px] border border-black/20 bg-white px-4 text-[13px] font-extrabold text-[#233a6b] shadow-[0_8px_18px_rgba(17,39,84,0.04)] transition hover:bg-[#f8fbff] sm:w-auto"
          >
            <X className="size-4" />
            Cancel
          </button>
          <button
            type="submit"
            form="create-lead-form"
            disabled={submitting}
            data-action="create-lead-save"
            className="inline-flex h-11 w-full items-center justify-center gap-2 rounded-[8px] border border-black/20 bg-[#10a64e] px-4 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(18,165,79,0.22)] transition hover:-translate-y-0.5 hover:bg-[#0e9145] disabled:opacity-60 sm:w-auto"
          >
            <Save className="size-4" />
            {submitting ? 'Saving...' : 'Save Lead'}
          </button>
        </div>
      </div>

      {submitError ? (
        <div className="rounded-[8px] border border-red-200 bg-red-50 px-4 py-3 text-[13px] font-bold text-red-600">
          {submitError}
        </div>
      ) : null}

      <form
        id="create-lead-form"
        className="grid items-start gap-4 xl:grid-cols-2"
        onSubmit={handleSubmit}
      >
        <LeadFormSection
          title="1. Basic Information"
          icon={ReceiptText}
          tone="success"
        >
          <div className="grid gap-4 lg:grid-cols-3">
            <LeadInput label="Customer Name" required icon={UserRound} placeholder="Enter customer name" name="customer_name" />
            <LeadPhoneInput label="Mobile Number" required placeholder="Enter mobile number" name="mobile_number" />
            <IvrsVerifyField
              checking={ivrsCheck.checking}
              result={ivrsCheck.result}
              onCheck={ivrsCheck.check}
              onReset={ivrsCheck.reset}
              onShowDetail={setViewDuplicateLeadId}
            />
          </div>
          <div className="grid gap-4 lg:grid-cols-2">
            <LeadPhoneInput label="Alternate Number" placeholder="Enter alternate number" name="alternate_number" />
            <LeadInput label="Email Address" icon={Mail} placeholder="Enter email address" type="email" name="email" />
          </div>
        </LeadFormSection>

        <LeadFormSection title="2. Project Information" icon={ClipboardPlus} tone="primary">
          <div className="grid gap-4 lg:grid-cols-2">
            <LeadInput label="Project Name" icon={FolderKanban} placeholder="Enter project name" name="project_name" />
            <LeadSelect label="Project Type" placeholder="Select project type" options={['On-Grid', 'Off-Grid', 'Hybrid']} name="project_type" />
          </div>
          <LeadTextarea label="Requirement Details" icon={Users} placeholder="Enter requirement details..." name="requirement_details" />
          <div className="grid gap-4 lg:grid-cols-2">
            <LeadSelect label="Source" placeholder="Select source" options={['Website', 'Referral', 'Walk-in', 'Campaign']} name="source" />
            <LeadInput label="Estimated Capacity (kW)" icon={Zap} type="number" placeholder="Enter capacity (e.g. 5, 10, 20)" name="estimated_capacity" />
          </div>
        </LeadFormSection>

        <LeadFormSection title="3. Assignment & Follow-up" icon={UserRound} tone="purple">
          <div className="grid gap-4 lg:grid-cols-3">
            <LeadSelect label="Assigned Employee" required placeholder={employeeOptions.length ? 'Select employee' : 'No active employees found'} options={employeeOptions} name="assigned_to" />
            <LeadDateInput label="Follow-up Date" required name="next_follow_up" />
            <LeadSelect label="Lead Status" placeholder="New" options={['New', 'Follow-up', 'Quotation', 'Lost']} badgeValue="New" name="status" />
          </div>
          <div className="grid gap-4 lg:grid-cols-2">
            <LeadTextarea label="Remarks" icon={MapPin} placeholder="Enter remarks (optional)" compact name="remarks" />
          </div>
        </LeadFormSection>

        <LeadFormSection title="4. Location Information" titleSuffix="(Optional)" icon={MapPin} tone="warning">
          <LeadTextarea label="Address" icon={MapPin} placeholder="Enter full address" name="address" />
          <div className="grid gap-4 lg:grid-cols-2">
            <LeadInput label="Latitude" optional icon={MapPin} placeholder="Enter latitude" name="latitude" />
            <LeadInput label="Longitude" optional icon={MapPin} placeholder="Enter longitude" name="longitude" />
          </div>
        </LeadFormSection>

        <CreateLeadNotice />
      </form>

      <DashboardFooter />

      {duplicateModalOpen ? (
        <DuplicateIvrsModal
          ivrsNumber={duplicateIvrs}
          existingLeads={duplicateLeadMatches}
          requestedLead={duplicateLeadPayload}
          onClose={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
          }}
          onRequestApproval={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
            onRequestApproval();
          }}
          onNotify={onNotify}
        />
      ) : null}

      {viewDuplicateLeadId ? (
        <LeadViewModal
          leadId={viewDuplicateLeadId}
          onClose={() => setViewDuplicateLeadId(null)}
          onEdit={() => setViewDuplicateLeadId(null)}
          onNotify={onNotify}
        />
      ) : null}
    </div>
  );
}

function LeadFormModal({ mode = 'create', lead, projectContext = null, projectCreate = false, onClose, onSaved, onRequestApproval, onNotify }) {
  const [duplicateModalOpen, setDuplicateModalOpen] = useState(false);
  const [duplicateIvrs, setDuplicateIvrs] = useState('');
  const [duplicateLeadMatches, setDuplicateLeadMatches] = useState([]);
  const [duplicateLeadPayload, setDuplicateLeadPayload] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [employeeOptions, setEmployeeOptions] = useState(cachedEmployeeOptions || []);
  const [detail, setDetail] = useState(mode === 'edit' ? null : {});
  const [loadingDetail, setLoadingDetail] = useState(mode === 'edit');
  const formRef = useRef(null);
  const [quotationTemplate, setQuotationTemplate] = useState('');
  const [quotationDetail, setQuotationDetail] = useState(null);
  const [showQuotationDetailModal, setShowQuotationDetailModal] = useState(false);
  const [viewDuplicateLeadId, setViewDuplicateLeadId] = useState(null);
  const ivrsCheck = useIvrsCheck(lead?.id);
  // "Project Details Update" (edit) aur "New Project" (create) dono project popups —
  // in dono me lead status fixed 'Won' rehta hai aur follow-up date optional hai.
  const projectMode = Boolean(projectContext) || projectCreate;

  useEffect(() => {
    getEmployeeOptions().then(setEmployeeOptions);
  }, []);

  useEffect(() => {
    if (mode !== 'edit' || !lead?.id) { setDetail({}); setLoadingDetail(false); return; }
    setLoadingDetail(true);
    leadApi.get(lead.id).then((data) => setDetail(data || {})).catch(() => setDetail({})).finally(() => setLoadingDetail(false));
  }, [mode, lead?.id]);

  const handleSubmit = async (event) => {
    event.preventDefault();
    const fd = new FormData(event.currentTarget);
    const mobile = fd.get('mobile_number')?.trim();
    const ivrs = fd.get('ivrs_number')?.trim();

    setSubmitting(true);
    setSubmitError('');
    const payload = {
      customer_name: fd.get('customer_name'),
      mobile_number: mobile,
      ivrs_number: ivrs || undefined,
      alternate_number: fd.get('alternate_number') || undefined,
      email: fd.get('email') || undefined,
      project_name: fd.get('project_name') || undefined,
      project_type: fd.get('project_type') || undefined,
      requirement_details: fd.get('requirement_details') || undefined,
      source: fd.get('source') || undefined,
      estimated_capacity: fd.get('estimated_capacity') || undefined,
      next_follow_up: fd.get('next_follow_up') || undefined,
      assigned_to: fd.get('assigned_to') || undefined,
      status: projectMode ? 'Won' : (fd.get('status') || 'New'),
      remarks: fd.get('remarks') || undefined,
      address: fd.get('address') || undefined,
      city: fd.get('city') || undefined,
      state: fd.get('state') || undefined,
      latitude: fd.get('latitude') || undefined,
      longitude: fd.get('longitude') || undefined,
    };

    try {
      if (projectContext) {
        await projectApi.update(projectContext.projectId, { status: fd.get('project_status') || projectContext.status });
        const savedProjectLead = projectContext.leadId ? await leadApi.update(projectContext.leadId, payload) : null;
        onNotify?.('Project details updated successfully!');
        onSaved?.(savedProjectLead);
        return;
      }
      let savedLead;
      if (mode === 'edit') {
        savedLead = await leadApi.update(lead.id, payload);
        onNotify?.('Lead updated successfully!');
      } else {
        savedLead = await leadApi.create(payload);
        // New Project: 'Won' lead create karte hi backend signal apne aap Project bana deta hai
        // (status 'Planning'). Agar user ne dusra status chuna hai to wo project pe apply kar do.
        if (projectCreate) {
          const chosenStatus = fd.get('project_status') || 'Planning';
          if (chosenStatus && chosenStatus !== 'Planning') {
            try {
              const projs = await projectApi.list({ lead: savedLead.id });
              const list = Array.isArray(projs) ? projs : projs?.results ?? [];
              if (list[0]?.id) await projectApi.update(list[0].id, { status: chosenStatus });
            } catch { /* status update non-fatal */ }
          }
        }
        onNotify?.(projectCreate ? 'Project created successfully!' : 'Lead created successfully!');
      }

      if (quotationDetail) {
        quotationApi.create(buildQuotationDetailPayload(quotationDetail.template, quotationDetail.form, savedLead.id, quotationDetail.items)).catch(() => {});
      }

      onSaved?.(savedLead);
    } catch (err) {
      if (mode === 'create' && err.message?.toLowerCase().includes('ivrs number already exists')) {
        const matches = await leadApi.list({ search: ivrs }).catch(() => null);
        const matchRows = matches ? (Array.isArray(matches) ? matches : matches.results ?? []) : [];
        setDuplicateLeadMatches(matchRows.filter((row) => row.ivrs_number === ivrs));
        setDuplicateLeadPayload(payload);
        setDuplicateIvrs(ivrs);
        setDuplicateModalOpen(true);
      } else {
        setSubmitError(err.message || 'Error saving lead. Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  };

  const d = detail || {};
  const followUpDateValue = d.next_follow_up ? new Date(d.next_follow_up).toISOString().slice(0, 10) : '';

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/55 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[92vh] w-full max-w-[860px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between border-b border-[#edf2f8] px-6 py-4">
          <h2 className="font-display text-[18px] font-extrabold text-[#111827]">
            {projectContext ? 'Project Details Update' : projectCreate ? 'New Project' : mode === 'edit' ? 'Edit Lead' : 'Create Lead'}
          </h2>
          <button type="button" onClick={onClose} aria-label="Close" title="Close" className="text-[#7585a2]"><X className="size-5" /></button>
        </div>

        <div className="scroll-soft flex-1 overflow-y-auto p-6">
          {submitError ? (
            <div className="mb-4 rounded-[8px] border border-red-200 bg-red-50 px-4 py-3 text-[13px] font-bold text-red-600">
              {submitError}
            </div>
          ) : null}

          {loadingDetail ? (
            <PageLoadingState message="Loading lead..." />
          ) : (
          <form id="lead-form-modal" ref={formRef} className="space-y-4" onSubmit={handleSubmit}>
            {projectMode ? (
              <LeadFormSection title="Project Status" icon={FolderKanban} tone="primary">
                <div className="grid gap-4 lg:grid-cols-3">
                  <LeadSelect label="Status" placeholder="Select status" options={['Planning', 'Active', 'On Hold', 'Completed', 'Cancelled']} name="project_status" defaultValue={projectContext ? projectContext.status : 'Planning'} />
                </div>
              </LeadFormSection>
            ) : null}
            <LeadFormSection title="1. Basic Information" icon={ReceiptText} tone="success">
              <div className="grid gap-4 lg:grid-cols-3">
                <LeadInput label="Customer Name" required icon={UserRound} placeholder="Enter customer name" name="customer_name" defaultValue={d.customer_name} />
                <LeadPhoneInput label="Mobile Number" required placeholder="Enter mobile number" name="mobile_number" defaultValue={d.mobile_number} />
                <IvrsVerifyField
                  defaultValue={d.ivrs_number}
                  checking={ivrsCheck.checking}
                  result={ivrsCheck.result}
                  onCheck={ivrsCheck.check}
                  onReset={ivrsCheck.reset}
                  onShowDetail={setViewDuplicateLeadId}
                />
              </div>
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadPhoneInput label="Alternate Number" placeholder="Enter alternate number" name="alternate_number" defaultValue={d.alternate_number} />
                <LeadInput label="Email Address" icon={Mail} placeholder="Enter email address" type="email" name="email" defaultValue={d.email} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="2. Project Information" icon={ClipboardPlus} tone="primary">
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadInput label="Project Name" icon={FolderKanban} placeholder="Enter project name" name="project_name" defaultValue={d.project_name} />
                <LeadSelect label="Project Type" placeholder="Select project type" options={['On-Grid', 'Off-Grid', 'Hybrid']} name="project_type" defaultValue={d.project_type} />
              </div>
              <LeadTextarea label="Requirement Details" icon={Users} placeholder="Enter requirement details..." name="requirement_details" defaultValue={d.requirement_details} />
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadSelect label="Source" placeholder="Select source" options={['Website', 'Referral', 'Walk-in', 'Campaign']} name="source" defaultValue={d.source} />
                <LeadInput label="Estimated Capacity (kW)" icon={Zap} type="number" placeholder="Enter capacity (e.g. 5, 10, 20)" name="estimated_capacity" defaultValue={d.estimated_capacity} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="3. Assignment & Follow-up" icon={UserRound} tone="purple">
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadDateInput label="Follow-up Date" required={!projectMode} name="next_follow_up" defaultValue={followUpDateValue} />
                {projectMode ? (
                  <LeadLockedField label="Lead Status" value="Won" />
                ) : (
                  <LeadSelect label="Lead Status" placeholder="New" options={['New', 'Follow-up', 'Quotation', 'Won', 'Lost']} badgeValue={mode === 'create' ? 'New' : undefined} name="status" defaultValue={d.status} />
                )}
              </div>
              <LeadTextarea label="Remarks" icon={MapPin} placeholder="Enter remarks (optional)" compact name="remarks" defaultValue={d.remarks} />
            </LeadFormSection>

            <LeadFormSection title="4. Location Information" titleSuffix="(Optional)" icon={MapPin} tone="warning">
              <LeadTextarea label="Address" icon={MapPin} placeholder="Enter full address" name="address" defaultValue={d.address} />
              <div className="grid gap-4 lg:grid-cols-2">
                <LeadInput label="Latitude" optional icon={MapPin} placeholder="Enter latitude" name="latitude" defaultValue={d.latitude} />
                <LeadInput label="Longitude" optional icon={MapPin} placeholder="Enter longitude" name="longitude" defaultValue={d.longitude} />
              </div>
            </LeadFormSection>

            <LeadFormSection title="5. Quotation" titleSuffix="(Optional)" icon={ReceiptText} tone="primary">
              <p className="-mt-1 mb-1 text-[12px] font-bold text-[#7386a3]">Pick a quotation template, fill its detail in a separate form, then save it here. Manage full quotations later from the lead's details page.</p>
              <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
                {QUOTATION_TEMPLATE_OPTIONS.map((option) => {
                  const active = quotationTemplate === option;
                  const savedForThis = quotationDetail && quotationTemplate === option;
                  return (
                    <button
                      key={option}
                      type="button"
                      onClick={() => setQuotationTemplate(option)}
                      className={cx(
                        'flex items-center justify-between gap-2 rounded-[10px] border px-4 py-3 text-left text-[13px] font-extrabold transition',
                        active ? 'border-[#0b65e5] bg-[#edf5ff] text-[#0b65e5]' : 'border-[#dbe5f2] bg-white text-[#30466d] hover:bg-[#f8fbff]',
                      )}
                    >
                      {option}
                      {savedForThis ? <CheckCircle2 className="size-4 shrink-0 text-[#0d9f4a]" /> : null}
                    </button>
                  );
                })}
              </div>
              <button
                type="button"
                disabled={!quotationTemplate}
                onClick={() => setShowQuotationDetailModal(true)}
                className="inline-flex h-11 items-center gap-2 rounded-[8px] border border-[#0b65e5] bg-white px-4 text-[13px] font-extrabold text-[#0b65e5] transition hover:bg-[#edf5ff] disabled:cursor-not-allowed disabled:opacity-50"
              >
                <FileText className="size-4" />
                {quotationDetail && quotationTemplate === quotationDetail.template ? 'Edit Detail' : 'Fill Detail'}
              </button>
              {quotationDetail && quotationTemplate === quotationDetail.template ? (
                <p className="text-[12px] font-bold text-[#087a39]">Detail saved for {quotationDetail.template}. It will be created with this lead.</p>
              ) : null}
            </LeadFormSection>

            <LeadFormSection title="6. Assigned To" titleSuffix="(Optional)" icon={UserRound} tone="purple">
              <LeadSelect label="Assigned Employee" optional placeholder={employeeOptions.length ? 'Select employee' : 'No active employees found'} options={employeeOptions} name="assigned_to" defaultValue={d.assigned_to ? String(d.assigned_to) : ''} />
            </LeadFormSection>
          </form>
          )}
        </div>

        <div className="flex flex-col justify-end gap-3 border-t border-[#edf2f8] px-6 py-4 sm:flex-row">
          <button type="button" onClick={onClose} className="h-11 rounded-[8px] border border-black/20 bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">
            Cancel
          </button>
          <button
            type="submit"
            form="lead-form-modal"
            disabled={submitting || loadingDetail}
            className="inline-flex h-11 items-center justify-center gap-2 rounded-[8px] bg-[#10a64e] px-5 text-[13px] font-extrabold text-white shadow-[0_12px_22px_rgba(18,165,79,0.22)] transition hover:bg-[#0e9145] disabled:opacity-60"
          >
            <Save className="size-4" />
            {submitting ? 'Saving...' : projectContext ? 'Update Project' : projectCreate ? 'Create Project' : mode === 'edit' ? 'Update Lead' : 'Save Lead'}
          </button>
        </div>
      </div>

      {duplicateModalOpen ? (
        <DuplicateIvrsModal
          ivrsNumber={duplicateIvrs}
          existingLeads={duplicateLeadMatches}
          requestedLead={duplicateLeadPayload}
          onClose={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
          }}
          onRequestApproval={() => {
            setDuplicateModalOpen(false);
            setDuplicateLeadPayload(null);
            onRequestApproval?.();
          }}
          onNotify={onNotify}
        />
      ) : null}

      {showQuotationDetailModal ? (
        <QuotationDetailModal
          template={quotationTemplate}
          initialForm={quotationTemplate === quotationDetail?.template ? quotationDetail.form : null}
          initialItems={quotationTemplate === quotationDetail?.template ? quotationDetail.items : null}
          leadSnapshot={(() => {
            const snap = formRef.current ? new FormData(formRef.current) : null;
            return {
              customer_name: snap?.get('customer_name') || '',
              mobile_number: snap?.get('mobile_number') || '',
              alternate_number: snap?.get('alternate_number') || '',
              email: snap?.get('email') || '',
              address: snap?.get('address') || '',
              project_name: snap?.get('project_name') || '',
              source: snap?.get('source') || '',
            };
          })()}
          onClose={() => setShowQuotationDetailModal(false)}
          onTemplateChange={setQuotationTemplate}
          onSave={(savedTemplate, form, items) => {
            setQuotationTemplate(savedTemplate);
            setQuotationDetail({ template: savedTemplate, form, items });
            setShowQuotationDetailModal(false);
          }}
        />
      ) : null}

      {viewDuplicateLeadId ? (
        <LeadViewModal
          leadId={viewDuplicateLeadId}
          onClose={() => setViewDuplicateLeadId(null)}
          onEdit={() => setViewDuplicateLeadId(null)}
          onNotify={onNotify}
        />
      ) : null}
    </div>
  );
}

function localDateKey(value) {
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return null;
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

// Lead List ke "View Follow-up" button se khulta hai — Today/Tomorrow/kisi bhi date ke
// saare leads ke follow-ups ek jagah dekhne ke liye, bina poori list filter kiye.
function LeadFollowUpsOverviewModal({ leads, onClose, onViewLead }) {
  const [filterMode, setFilterMode] = useState('all');
  const [customDate, setCustomDate] = useState('');

  const todayKey = localDateKey(new Date());
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowKey = localDateKey(tomorrow);
  const targetKey = filterMode === 'today' ? todayKey : filterMode === 'tomorrow' ? tomorrowKey : customDate;

  const filteredLeads = useMemo(() => {
    if (!leads || (filterMode === 'date' && !customDate)) return [];
    return leads
      .filter((lead) => lead.nextFollowUpRaw && (filterMode === 'all' || localDateKey(lead.nextFollowUpRaw) === targetKey))
      .sort((a, b) => new Date(a.nextFollowUpRaw) - new Date(b.nextFollowUpRaw));
  }, [leads, filterMode, customDate, targetKey]);

  const tabs = [
    { key: 'all', label: 'All Follow-ups' },
    { key: 'today', label: 'Today' },
    { key: 'tomorrow', label: 'Tomorrow' },
    { key: 'date', label: 'Pick a Date' },
  ];

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/50 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in flex max-h-[88vh] w-full max-w-[720px] flex-col overflow-hidden rounded-[16px] bg-white shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-center justify-between gap-3 border-b border-[#edf2f8] px-6 py-5">
          <h2 className="flex items-center gap-3 font-display text-[18px] font-extrabold text-[#111827]"><CalendarDays className="size-5 text-[#0b65e5]" /> Follow-ups</h2>
          <button type="button" onClick={onClose} className="text-[#7585a2] hover:text-[#111827]"><X className="size-5" /></button>
        </div>

        <div className="flex flex-wrap items-center gap-2 border-b border-[#edf2f8] px-6 py-4">
          {tabs.map((tab) => (
            <button
              key={tab.key}
              type="button"
              onClick={() => setFilterMode(tab.key)}
              className={cx(
                'rounded-[8px] px-4 py-2 text-[13px] font-extrabold transition',
                filterMode === tab.key ? 'bg-[#0b65e5] text-white' : 'border border-[#d9e4f2] bg-white text-[#284276] hover:bg-[#f8fbff]',
              )}
            >
              {tab.label}
            </button>
          ))}
          {filterMode === 'date' ? (
            <input
              type="date"
              value={customDate}
              onChange={(event) => setCustomDate(event.target.value)}
              className="h-10 rounded-[8px] border border-[#d9e4f2] bg-white px-3 text-[13px] font-bold text-[#30466d] outline-none transition focus:border-blue-500 focus:ring-4 focus:ring-blue-100"
            />
          ) : null}
          <span className="ml-auto text-[12px] font-bold text-[#7b88a2]">{filteredLeads.length} follow-up{filteredLeads.length === 1 ? '' : 's'}</span>
        </div>

        <div className="scroll-soft divide-y divide-[#edf2f8] overflow-y-auto px-6">
          {!leads ? (
            <PageLoadingState message="Loading follow-ups..." compact />
          ) : filterMode === 'date' && !customDate ? (
            <p className="py-8 text-center text-[13px] font-bold text-[#53647f]">Pick a date to see follow-ups.</p>
          ) : filteredLeads.length === 0 ? (
            <p className="py-8 text-center text-[13px] font-bold text-[#53647f]">{filterMode === 'all' ? 'No follow-ups scheduled.' : 'No follow-ups scheduled for this day.'}</p>
          ) : filteredLeads.map((lead) => (
            <div key={lead.id} className="flex flex-wrap items-center justify-between gap-3 py-4">
              <div className="min-w-0">
                <p className="font-extrabold text-[#1e3261]">{lead.customer}</p>
                <p className="mt-0.5 text-[12px] font-bold text-[#53647f]">{lead.project} • {lead.mobile}</p>
              </div>
              <div className="flex items-center gap-4">
                <AssigneeCell assignee={lead.assignedTo} compact />
                <span className="text-[13px] font-extrabold text-[#0b65e5]">
                  {filterMode === 'all'
                    ? new Date(lead.nextFollowUpRaw).toLocaleString('en-IN', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' })
                    : new Date(lead.nextFollowUpRaw).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}
                </span>
                <button
                  type="button"
                  onClick={() => onViewLead(lead.id)}
                  className="inline-flex size-8 items-center justify-center rounded-[8px] border border-[#e3ebf7] bg-white text-[#3480ff] transition hover:bg-[#f5f9ff]"
                  aria-label={`View ${lead.customer}`}
                >
                  <Eye className="size-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
        <div className="h-5 shrink-0" />
      </div>
    </div>
  );
}

function LeadViewModal({ leadId, onClose, onEdit, onNotify }) {
  const [detail, setDetail] = useState(null);
  const [loading, setLoading] = useState(true);
  const [addFollowUpOpen, setAddFollowUpOpen] = useState(false);

  useEffect(() => {
    setLoading(true);
    leadApi.get(leadId).then((data) => setDetail(data)).catch(() => setDetail(null)).finally(() => setLoading(false));
  }, [leadId]);

  return (
    <div
      className="modal-overlay fixed inset-0 z-95 flex items-center justify-center bg-[#111827]/50 p-4"
      onMouseDown={(event) => { if (event.target === event.currentTarget) onClose(); }}
    >
      <div className="modal-pop-in scroll-soft flex max-h-[90vh] w-full max-w-[640px] flex-col overflow-y-auto rounded-[16px] bg-white p-6 shadow-[0_30px_70px_rgba(17,24,39,0.28)]">
        <div className="flex items-start justify-between gap-4">
          <h2 className="font-display text-[19px] font-extrabold text-[#111827]">Lead Details</h2>
          <button type="button" onClick={onClose} aria-label="Close" title="Close" className="text-[#7585a2]"><X className="size-5" /></button>
        </div>
        {loading ? (
          <PageLoadingState message="Loading lead details..." compact />
        ) : !detail ? (
          <p className="py-12 text-center text-[13px] font-bold text-[#7386a3]">Lead not found.</p>
        ) : (
          <>
            <div className="mt-5 grid gap-3 sm:grid-cols-2">
              <InfoCell large label="Customer Name" value={detail.customer_name} />
              <InfoCell large label="Mobile Number" value={detail.mobile_number} />
              <InfoCell large label="IVRS Number" value={detail.ivrs_number || '—'} />
              <InfoCell large label="Email" value={detail.email || '—'} />
              <InfoCell large label="Project Name" value={detail.project_name || '—'} />
              <InfoCell large label="Project Type" value={detail.project_type || '—'} />
              <InfoCell large label="Estimated Capacity" value={detail.estimated_capacity ? `${formatCapacityKw(detail.estimated_capacity).trim()}` : '—'} />
              <InfoCell large label="Status" valueNode={<StatusBadge status={detail.status} />} />
              <InfoCell large label="Assigned To" value={detail.assigned_to_detail?.name || 'Unassigned'} />
              <InfoCell large label="Next Follow-up" value={detail.next_follow_up ? new Date(detail.next_follow_up).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : '—'} />
              <InfoCell large label="Source" value={detail.source || '—'} />
            </div>
            {detail.address ? (
              <div className="mt-4"><InfoCell large label="Address" value={detail.address} /></div>
            ) : null}
            {detail.remarks ? (
              <div className="mt-4"><InfoCell large label="Remarks" value={detail.remarks} /></div>
            ) : null}
            <div className="mt-6 flex flex-wrap justify-end gap-3">
              <button type="button" onClick={onClose} className="h-10 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#233a6b] transition hover:bg-[#f8fbff]">Close</button>
              <button type="button" onClick={() => setAddFollowUpOpen(true)} className="inline-flex h-10 items-center gap-2 rounded-[8px] bg-[#0d9f4a] px-5 text-[13px] font-extrabold text-white transition hover:bg-[#078c3e]"><Plus className="size-4" />Add Follow-up</button>
              <button type="button" onClick={onEdit} className="inline-flex h-10 items-center gap-2 rounded-[8px] border border-[#d9e4f2] bg-white px-5 text-[13px] font-extrabold text-[#0b65e5] transition hover:bg-[#f8fbff]"><Pencil className="size-4" />Edit Lead</button>
            </div>
          </>
        )}
      </div>

      {addFollowUpOpen && detail ? (
        <LeadQuickActionModal
          type="follow-up"
          lead={{ id: leadId, customer: detail.customer_name, mobile: detail.mobile_number, ivrs: detail.ivrs_number }}
          onClose={() => setAddFollowUpOpen(false)}
          onSaved={() => setAddFollowUpOpen(false)}
          onNotify={onNotify}
        />
      ) : null}
    </div>
  );
}

