function fieldsFromQuotation(q) {
  const base = emptyQuotationFields();
  const next = { ...base };
  Object.keys(base).forEach((key) => {
    if (q[key] === null || q[key] === undefined) return;
    next[key] = typeof base[key] === 'boolean' ? Boolean(q[key]) : String(q[key]);
  });
  return next;
}

